ype = spec.StringOrArray{g.Type}\n60: \t}\n61: \tret.Nullable = g.Nullable\n62: \tret.Description = g.Description\n63: \tret.Title = g.Title\n64: \tret.Default = g.Default.Object\n65: }\n66: \n67: func (x *Extensions) toKubeOpenAPI(ret *spec.Schema) {\n68: \tif x == nil {\n69: \t\treturn\n70: \t}\n71: \n72: \tif x.XPreserveUnknownFields {\n73: \t\tret.VendorExtensible.AddExtension(\"x-kubernetes-preserve-unknown-fields\", true)\n74: \t}\n75: \tif x.XEmbeddedResource {\n76: \t\tret.VendorExtensible.AddExtension(\"x-kubernetes-embedded-resource\", true)\n77: \t}\n78: \tif x.XIntOrString {\n79: \t\tret.VendorExtensible.AddExtension(\"x-kubernetes-int-or-string\", true)\n80: \t}\n81: \tif len(x.XListMapKeys) \u003e 0 {\n82: \t\tret.VendorExtensible.AddExtension(\"x-kubernetes-list-map-keys\", x.XListMapKeys)\n83: \t}\n84: \tif x.XListType != nil {\n85: \t\tret.VendorExtensible.AddExtension(\"x-kubernetes-list-type\", *x.XListType)\n86: \t}\n87: \tif x.XMapType != nil {\n88: \t\tret.VendorExtensible.AddExtension(\"x-kubernetes-map-type\", *x.XMapType)\n89: \t}\n90: }\n91: \n92: func (x *ValidationExtensions) toKubeOpenAPI(ret *spec.Schema) {\n93: \tif x == nil {\n94: \t\treturn\n95: \t}\n96: \n97: \tif len(x.XValidations) \u003e 0 {\n98: \t\tret.VendorExtensible.AddExtension(\"x-kubernetes-validations\", x.XValidations)\n99: \t}\n100: }\n101: \n102: func (v *ValueValidation) toKubeOpenAPI(ret *spec.Schema) {\n103: \tif v == nil {\n104: \t\treturn\n105: \t}\n106: \n107: \tret.Format = v.Format\n108: \tret.Maximum = v.Maximum\n109: \tret.ExclusiveMaximum = v.ExclusiveMaximum\n110: \tret.Minimum = v.Minimum\n111: \tret.ExclusiveMinimum = v.ExclusiveMinimum\n112: \tret.MaxLength = v.MaxLength\n113: \tret.MinLength = v.MinLength\n114: \tret.Pattern = v.Pattern\n115: \tret.MaxItems = v.MaxItems\n116: \tret.MinItems = v.MinItems\n117: \tret.UniqueItems = v.UniqueItems\n118: \tret.MultipleOf = v.MultipleOf\n119: \tif v.Enum != nil {\n120: \t\tret.Enum = make([]interface{}, 0, len(v.Enum))\n121: \t\tfor i := range v.Enum {\n122: \t\t\tret.Enum = append(ret.Enum, v.Enum[i].Object)\n123: \t\t}\n124: \t}\n125: \tret.MaxProperties = v.MaxProperties\n126: \tret.MinProperties = v.MinProperties\n127: \tret.Required = v.Required\n128: \tfor i := range v.AllOf {\n129: \t\tret.AllOf = append(ret.AllOf, *v.AllOf[i].toKubeOpenAPI())\n130: \t}\n131: \tfor i := range v.AnyOf {\n132: \t\tret.AnyOf = append(ret.AnyOf, *v.AnyOf[i].toKubeOpenAPI())\n133: \t}\n134: \tfor i := range v.OneOf {\n135: \t\tret.OneOf = append(ret.OneOf, *v.OneOf[i].toKubeOpenAPI())\n136: \t}\n137: \tret.Not = v.Not.toKubeOpenAPI()\n138: }\n139: \n140: func (vv *NestedValueValidation) toKubeOpenAPI() *spec.Schema {\n141: \tif vv == nil {\n142: \t\treturn nil\n143: \t}\n144: \n145: \tret := \u0026spec.Schema{}\n146: \n147: \tvv.ValueValidation.toKubeOpenAPI(ret)\n148: \tvv.ValidationExtensions.toKubeOpenAPI(ret)\n149: \tif vv.Items != nil {\n150: \t\tret.Items = \u0026spec.SchemaOrArray{Schema: vv.Items.toKubeOpenAPI()}\n151: \t}\n152: \tif vv.Properties != nil {\n153: \t\tret.Properties = make(map[string]spec.Schema, len(vv.Properties))\n154: \t\tfor k, v := range vv.Properties {\n155: \t\t\tret.Properties[k] = *v.toKubeOpenAPI()\n156: \t\t}\n157: \t}\n158: \tvv.ForbiddenGenerics.toKubeOpenAPI(ret)   // normally empty. Exception: int-or-string\n159: \tvv.ForbiddenExtensions.toKubeOpenAPI(ret) // shouldn't do anything\n160: \treturn ret\n161: }\n162: ","url":"https://sourcegraph.sourcegraph.com/github.com/sg-evals/kubernetes--v1.32.0@d17b464c6fcd3273e4b1f695890bf0af7d5b272d/-/blob/staging/src/k8s.io/apiextensions-apiserver/pkg/apiserver/schema/kubeopenapi.go"}", "annotations": null, "meta": null}], "structuredContent": {"content": "1: /*
