{"meta": null, "content": [{"type": "text", "text": "{"content":"1: /*\n2: Copyright 2021 The Kubernetes Authors.\n3: \n4: Licensed under the Apache License, Version 2.0 (the \"License\");\n5: you may not use this file except in compliance with the License.\n6: You may obtain a copy of the License at\n7: \n8:     http://www.apache.org/licenses/LICENSE-2.0\n9: \n10: Unless required by applicable law or agreed to in writing, software\n11: distributed under the License is distributed on an \"AS IS\" BASIS,\n12: WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.\n13: See the License for the specific language governing permissions and\n14: limitations under the License.\n15: */\n16: \n17: package openapiv3\n18: \n19: import (\n20: \t\"fmt\"\n21: \t\"reflect\"\n22: \t\"sync\"\n23: \t\"time\"\n24: \n25: \tapiextensionsfeatures \"k8s.io/apiextensions-apiserver/pkg/features\"\n26: \t\"k8s.io/apimachinery/pkg/api/errors\"\n27: \t\"k8s.io/apimachinery/pkg/labels\"\n28: \t\"k8s.io/apimachinery/pkg/runtime/schema\"\n29: \tutilruntime \"k8s.io/apimachinery/pkg/util/runtime\"\n30: \t\"k8s.io/apimachinery/pkg/util/wait\"\n31: \tutilfeature \"k8s.io/apiserver/pkg/util/feature\"\n32: \t\"k8s.io/client-go/tools/cache\"\n33: \t\"k8s.io/client-go/util/workqueue\"\n34: \t\"k8s.io/klog/v2\"\n35: \t\"k8s.io/kube-openapi/pkg/handler3\"\n36: \t\"k8s.io/kube-openapi/pkg/spec3\"\n37: \n38: \tapiextensionshelpers \"k8s.io/apiextensions-apiserver/pkg/apihelpers\"\n39: \tapiextensionsv1 \"k8s.io/apiextensions-apiserver/pkg/apis/apiextensions/v1\"\n40: \tinformers \"k8s.io/apiextensions-apiserver/pkg/client/informers/externalversions/apiextensions/v1\"\n41: \tlisters \"k8s.io/apiextensions-apiserver/pkg/client/listers/apiextensions/v1\"\n42: \t\"k8s.io/apiextensions-apiserver/pkg/controller/openapi/builder\"\n43: )\n44: \n45: // Controller watches CustomResourceDefinitions and publishes OpenAPI v3\n46: type Controller struct {\n47: \tcrdLister  listers.CustomResourceDefinitionLister\n48: \tcrdsSynced cache.InformerSynced\n49: \n50: \t// To allow injection for testing.\n51: \tsyncFn func(string) error\n52: \n53: \tqueue workqueue.TypedRateLimitingInterface[string]\n54: \n55: \topenAPIV3Service *handler3.OpenAPIService\n56: \n57: \t// specs per version and per CRD name\n58: \tlock             sync.Mutex\n59: \tspecsByGVandName map[schema.GroupVersion]map[string]*spec3.OpenAPI\n60: }\n61: \n62: // NewController creates a new Controller with input CustomResourceDefinition informer\n63: func NewController(crdInformer informers.CustomResourceDefinitionInformer) *Controller {\n64: \tc := \u0026Controller{\n65: \t\tcrdLister:  crdInformer.Lister(),\n66: \t\tcrdsSynced: crdInformer.Informer().HasSynced,\n67: \t\tqueue: workqueue.NewTypedRateLimitingQueueWithConfig(\n68: \t\t\tworkqueue.DefaultTypedControllerRateLimiter[string](),\n69: \t\t\tworkqueue.TypedRateLimitingQueueConfig[string]{Name: \"crd_openapi_v3_controller\"},\n70: \t\t),\n71: \t\tspecsByGVandName: map[schema.GroupVersion]map[string]*spec3.OpenAPI{},\n72: \t}\n73: \n74: \tcrdInformer.Informer().AddEventHandler(cache.ResourceEventHandlerFuncs{\n75: \t\tAddFunc:    c.addCustomResourceDefinition,\n76: \t\tUpdateFunc: c.updateCustomResourceDefinition,\n77: \t\tDeleteFunc: c.deleteCustomResourceDefinition,\n78: \t})\n79: \n80: \tc.syncFn = c.sync\n81: \treturn c\n82: }\n83: \n84: // Run sets openAPIAggregationManager and starts workers\n85: func (c *Controller) Run(openAPIV3Service *handler3.OpenAPIService, stopCh \u003c-chan struct{}) {\n86: \tdefer utilruntime.HandleCrash()\n87: \tdefer c.queue.ShutDown()\n88: \tdefer klog.Infof(\"Shutting down OpenAPI V3 controller\")\n89: \n90: \tklog.Infof(\"Starting OpenAPI V3 controller\")\n91: \n92: \tc.openAPIV3Service = openAPIV3Service\n93: \n94: \tif !cache.WaitForCacheSync(stopCh, c.crdsSynced) {\n95: \t\tutilruntime.HandleError(fmt.Errorf(\"timed out waiting for caches to sync\"))\n96: \t\treturn\n97: \t}\n98: \n99: \tcrds, err := c.crdLister.List(labels.Everything())\n100: \tif err != nil {\n101: \t\tutilruntime.HandleError(fmt.Errorf(\"failed to initially list all CRDs: %v\", err))\n102: \t\treturn\n103: \t}\n104: \tfor _, crd := range crds {\n105: \t\tif !apiextensionshelpers.IsCRDConditionTrue(crd, apiextensionsv1.Established) {\n106: \t\t\tcontinue\n107: \t\t}\n108: \t\tfor _, v := range crd.Spec.Versions {\n109: \t\t\tif !v.Served {\n110: \t\t\t\tcontinue\n111: \t\t\t}\n112: \t\t\tc.buildV3Spec(crd, crd.Name, v.Name)\n113: \t\t}\n114: \t}\n115: \n116: \t// only start one worker thread since its a slow moving API\n117: \tgo wait.Until(c.runWorker, time.Second, stopCh)\n118: \n119: \t\u003c-stopCh\n120: }\n121: \n122: func (c *Controller) runWorker() {\n123: \tfor c.processNextWorkItem() {\n124: \t}\n125: }\n126: \n127: func (c *Controller) processNextWorkItem() bool {\n128: \tkey, quit := c.queue.Get()\n129: \tif quit {\n130: \t\treturn false\n131: \t}\n132: \tdefer c.queue.Done(key)\n133: \n134: \t// log slow aggregations\n135: \tstart := time.Now()\n136: \tdefer func() {\n137: \t\telapsed := time.Since(start)\n138: \t\tif elapsed \u003e time.Second {\n139: \t\t\tklog.Warningf(\"slow openapi aggregation of %q: %s\", key, elapsed)\n140: \t\t}\n141: \t}()\n142: \n143: \terr := c.syncFn(key)\n144: \tif err == nil {\n145: \t\tc.queue.Forget(key)\n146: \t\treturn true\n147: \t}\n148: \n149: \tutilruntime.HandleError(fmt.Errorf(\"%v failed with: %v\", key, err))\n150: \tc.queue.AddRateLimited(key)\n151: \treturn true\n152: }\n153: \n154: func (c *Controller) sync(name string) error {\n155: \tc.lock.Lock()\n156: \tdefer c.lock.Unlock()\n157: \n158: \tcrd, err := c.crdLister.Get(name)\n159: \tif err != nil \u0026\u0026 !errors.IsNotFound(err) {\n160: \t\treturn err\n161: \t}\n162: \n163: \tif errors.IsNotFound(err) || !apiextensionshelpers.IsCRDConditionTrue(crd, apiextensionsv1.Established) {\n164: \t\tc.deleteCRD(name)\n165: \t\treturn nil\n166: \t}\n167: \n168: \tfor _, v := range crd.Spec.Versions {\n169: \t\tif !v.Served {\n170: \t\t\tcontinue\n171: \t\t}\n172: \t\tc.buildV3Spec(crd, name, v.Name)\n173: \t}\n174: \n175: \treturn nil\n176: }\n177: \n178: func (c *Controller) deleteCRD(name string) {\n179: \tfor gv, crdListForGV := range c.specsByGVandName {\n180: \t\t_, needOpenAPIUpdate := crdListForGV[name]\n181: \t\tif needOpenAPIUpdate {\n182: \t\t\tdelete(crdListForGV, name)\n183: \t\t\tif len(crdListForGV) == 0 {\n184: \t\t\t\tdelete(c.specsByGVandName, gv)\n185: \t\t\t}\n186: \t\t\tregenerationCounter.With(map[string]string{\"group\": gv.Group, \"version\": gv.Version, \"crd\": name, \"reason\": \"remove\"})\n187: \t\t\tc.updateGroupVersion(gv)\n188: \t\t}\n189: \t}\n190: }\n191: \n192: func (c *Controller) updateGroupVersion(gv schema.GroupVersion) error {\n193: \tif _, ok := c.specsByGVandName[gv]; !ok {\n194: \t\tc.openAPIV3Service.DeleteGroupVersion(groupVersionToOpenAPIV3Path(gv))\n195: \t\treturn nil\n196: \t}\n197: \n198: \tvar specs []*spec3.OpenAPI\n199: \tfor _, spec := range c.specsByGVandName[gv] {\n200: \t\tspecs = append(specs, spec)\n201: \t}\n202: \n203: \tmergedSpec, err := builder.MergeSpecsV3(specs...)\n204: \tif err != nil {\n205: \t\treturn fmt.Errorf(\"failed to merge specs: %v\", err)\n206: \t}\n207: \n208: \tc.openAPIV3Service.UpdateGroupVersion(groupVersionToOpenAPIV3Path(gv), mergedSpec)\n209: \treturn nil\n210: }\n211: \n212: func (c *Controller) updateCRDSpec(crd *apiextensionsv1.CustomResourceDefinition, name, versionName string, v3 *spec3.OpenAPI) error {\n213: \tgv := schema.GroupVersion{\n214: \t\tGroup:   crd.Spec.Group,\n215: \t\tVersion: versionName,\n216: \t}\n217: \n218: \t_, ok := c.specsByGVandName[gv]\n219: \treason := \"update\"\n220: \tif !ok {\n221: \t\treason = \"add\"\n222: \t\tc.specsByGVandName[gv] = map[string]*spec3.OpenAPI{}\n223: \t}\n224: \n225: \toldSpec, ok := c.specsByGVandName[gv][name]\n226: \tif ok {\n227: \t\tif reflect.DeepEqual(oldSpec, v3) {\n228: \t\t\t// no changes to CRD\n229: \t\t\tretur