38: 					s.ValueValidation.AllOf = nil
39: 					changed = true
40: 				}
41: 				if s.ValueValidation.OneOf != nil {
42: 					s.ValueValidation.OneOf = nil
43: 					changed = true
44: 				}
45: 				if s.ValueValidation.AnyOf != nil {
46: 					s.ValueValidation.AnyOf = nil
47: 					changed = true
48: 				}
49: 				if s.ValueValidation.Not != nil {
50: 					s.ValueValidation.Not = nil
51: 					changed = true
52: 				}
53: 			}
54: 
55: 			// https://github.com/kubernetes/kube-openapi/pull/143/files#diff-ce77fea74b9dd098045004410023e0c3R219
56: 			if s.Nullable {
57: 				s.Type = ""
