59: 
60: 				// untyped values break if items or properties are set in kubectl
61: 				// https://github.com/kubernetes/kube-openapi/pull/143/files#diff-62afddb578e9db18fb32ffb6b7802d92R183
62: 				s.Items = nil
63: 				s.Properties = nil
64: 
65: 				changed = true
66: 			}
67: 
68: 			if s.XPreserveUnknownFields {
69: 				// unknown fields break if items or properties are set in kubectl
70: 				s.Items = nil
71: 				s.Properties = nil
