81: 				changed = true
82: 			}
83: 
84: 			if s.XPreserveUnknownFields && s.Type == "object" {
85: 				// similar as above, kubectl doesn't properly handle object fields with `x-kubernetes-preserve-unknown-fields: true`
86: 				s.Type = ""
