110: func filterOut(ss []string, x string) ([]string, bool) {
111: 	var filtered []string
112: 	for i, s := range ss {
113: 		if s == x {
114: 			if filtered == nil {
115: 				filtered = make([]string, i, len(ss))
116: 				copy(filtered, ss[:i])
117: 			}
118: 		} else if filtered != nil {
119: 			filtered = append(filtered, s)
120: 		}
121: 	}
122: 	if filtered != nil {
123: 		if len(filtered) == 0 {
